   126→
   127→  // Analyze photo and create homework with maieutic approach
   128→  const handleSubmitPhoto = useCallback(async (photo: File): Promise<Homework> => {
   129→    // Convert to base64
   130→    const base64 = await fileToBase64(photo);
   131→
   132→    // Call vision API to analyze problem
   133→    const response = await fetch('/api/homework/analyze', {
   134→      method: 'POST',
   135→      headers: { 'Content-Type': 'application/json' },
   136→      body: JSON.stringify({
   137→        image: base64,
   138→        systemPrompt: MAIEUTIC_SYSTEM_PROMPT,
   139→      }),
   140→    });
   141→
   142→    if (!response.ok) {
   143→      // Fallback: create mock homework for demo
   144→      const mockHomework: Homework = {
   145→        id: crypto.randomUUID(),
   146→        title: 'Problema da analizzare',
   147→        subject: 'mathematics' as Subject,
   148→        problemType: 'Esercizio',
   149→        photoUrl: base64,
   150→        steps: [
   151→          {
   152→            id: '1',
   153→            description: 'Leggi attentamente il problema e identifica i dati',
   154→            hints: [
   155→              'Cosa ti viene chiesto di trovare?',
   156→              'Quali numeri o valori sono forniti?',
   157→              'Ci sono relazioni tra questi dati?',
   158→            ],
   159→            studentNotes: '',
   160→            completed: false,
   161→          },
   162→          {
   163→            id: '2',
   164→            description: 'Individua la formula o il metodo da applicare',
   165→            hints: [
   166→              'Che tipo di problema è?',
   167→              'Quali formule conosci per questo tipo di problema?',
   168→              'Come si collegano i dati alla formula?',
   169→            ],
   170→            studentNotes: '',
   171→            completed: false,
   172→          },
   173→          {
   174→            id: '3',
   175→            description: 'Applica il metodo passo dopo passo',
   176→            hints: [
   177→              'Qual è il primo calcolo da fare?',
   178→              'Stai usando le unità di misura corrette?',
   179→              'Il risultato intermedio ha senso?',
   180→            ],
   181→            studentNotes: '',
   182→            completed: false,
   183→          },
   184→          {
   185→            id: '4',
   186→            description: 'Verifica il risultato',
   187→            hints: [
   188→              'Il risultato risponde alla domanda?',
   189→              'Ha senso nel contesto del problema?',
   190→              'Hai incluso le unità di misura?',
