   594→}
   595→
   596→// Utility: Convert file to base64
   597→function fileToBase64(file: File): Promise<string> {
   598→  return new Promise((resolve, reject) => {
   599→    const reader = new FileReader();
   600→    reader.onload = () => resolve(reader.result as string);
   601→    reader.onerror = reject;
   602→    reader.readAsDataURL(file);
   603→  });
   604→}
