     2→ * Voice Tool Commands
     3→ *
     4→ * Defines tool schemas for Azure Realtime API and handles tool execution.
     5→ * Bridges voice commands to the real-time tool-events/tool-state system.
     6→ *
     7→ * Part of I-02: Voice Tool Commands
     8→ * Related: #25 Voice-First Tool Creation
     9→ */
    10→
    11→import { logger } from '@/lib/logger';
    12→import type { ToolType } from '@/lib/realtime/tool-events';
    13→import type { Subject } from '@/types';
    14→import { executeOnboardingTool } from './onboarding-tools';
    15→
    16→// ============================================================================
    17→// TYPES
    18→// ============================================================================
    19→
    20→/**
    21→ * Voice tool definition for Azure Realtime API.
    22→ */
    23→export interface VoiceToolDefinition {
    24→  type: 'function';
    25→  name: string;
    26→  description: string;
    27→  parameters: {
    28→    type: 'object';
    29→    properties: Record<string, unknown>;
    30→    required: string[];
    31→  };
    32→}
    33→
    34→/**
    35→ * Voice tool call result.
    36→ */
    37→export interface VoiceToolCallResult {
    38→  success: boolean;
    39→  toolId?: string;
    40→  toolType?: ToolType;
    41→  error?: string;
    42→  displayed?: boolean;
    43→}
    44→
    45→/**
    46→ * Arguments for create_mindmap tool.
    47→ */
    48→export interface CreateMindmapArgs {
    49→  title: string;
    50→  topic: string;
    51→  subject?: Subject;
    52→  nodes?: Array<{
    53→    id: string;
    54→    label: string;
    55→    parentId?: string;
    56→  }>;
    57→}
    58→
    59→/**
    60→ * Arguments for create_quiz tool.
    61→ */
    62→export interface CreateQuizArgs {
    63→  title: string;
