    12→/**
    13→ * Wikipedia API response types
    14→ */
    15→interface WikipediaSearchResult {
    16→  title: string;
    17→  pageid: number;
    18→  snippet: string;
    19→}
    20→
    21→interface WikipediaApiResponse {
    22→  query?: {
