    26→
    27→/**
    28→ * Strip HTML tags using character-by-character state machine
    29→ * This avoids regex-based multi-character bypass vulnerabilities
    30→ */
    31→function stripHtmlTags(html: string): string {
    32→  let result = '';
    33→  let inTag = false;
    34→
    35→  for (let i = 0; i < html.length; i++) {
    36→    const char = html[i];
    37→
    38→    if (char === '<') {
    39→      inTag = true;
    40→    } else if (char === '>') {
    41→      inTag = false;
    42→    } else if (!inTag) {
    43→      result += char;
    44→    }
    45→  }
    46→
    47→  return result;
    48→}
    49→
    50→/**
    51→ * Search Italian Wikipedia for educational content.
    52→ * Uses the MediaWiki API which is free and requires no API key.
    53→ */
    54→async function performWebSearch(query: string): Promise<SearchResult[]> {
    55→  const results: SearchResult[] = [];
    56→
    57→  try {
    58→    // Search Italian Wikipedia
    59→    const wikiUrl = new URL('https://it.wikipedia.org/w/api.php');
    60→    wikiUrl.searchParams.set('action', 'query');
    61→    wikiUrl.searchParams.set('list', 'search');
    62→    wikiUrl.searchParams.set('srsearch', query);
    63→    wikiUrl.searchParams.set('srlimit', '3');
    64→    wikiUrl.searchParams.set('format', 'json');
    65→    wikiUrl.searchParams.set('origin', '*');
    66→
    67→    const response = await fetch(wikiUrl.toString());
    68→    if (response.ok) {
    69→      const data: WikipediaApiResponse = await response.json();
    70→      const searchResults = data.query?.search || [];
    71→
    72→      for (const item of searchResults) {
    73→        // Strip HTML tags using character-by-character parsing (avoids regex bypass attacks)
    74→        // This handles all tag formats correctly without multi-character regex issues
    75→        const cleanSnippet = stripHtmlTags(item.snippet);
    76→
    77→        results.push({
    78→          type: 'web',
    79→          title: `${item.title} - Wikipedia`,
    80→          url: `https://it.wikipedia.org/wiki/${encodeURIComponent(item.title.replace(/ /g, '_'))}`,
    81→          description: cleanSnippet,
    82→        });
    83→      }
    84→    }
    85→  } catch (error) {
    86→    logger.error('Wikipedia search failed', { error, query });
    87→  }
    88→
    89→  // Always add Treccani link as authoritative Italian source
    90→  results.push({
    91→    type: 'web',
    92→    title: `Cerca "${query}" su Treccani`,
    93→    url: `https://www.treccani.it/enciclopedia/ricerca/${encodeURIComponent(query)}/`,
    94→    description: 'Enciclopedia Italiana - fonte autorevole per approfondimenti',
    95→  });
    96→
    97→  return results;
    98→}
